/// Draw a string using a proportional bitmap font.
/// Returns the total width drawn (for centering calculations).
pub fn draw_prop_text<D: DrawTarget<Color = Rgb565>>(
    display: &mut D,
    text: &str,
    x: i32,
    y: i32, // baseline y position
    color: Rgb565,
    widths: &[u8],
    offsets: &[u16],
    data: &[u8],
    height: u8,
    ascent: u8,
    first_char: u8,
    last_char: u8,
) -> i32 {
    let mut cx = x;
    let top_y = y - ascent as i32;
    
    for &ch in text.as_bytes() {
        if ch < first_char || ch > last_char {
            cx += (height / 3) as i32; // space for unknown chars
            continue;
        }
        let idx = (ch - first_char) as usize;
        let cw = widths[idx] as usize;
        let offset = offsets[idx] as usize;
        let row_bytes = (cw + 7) / 8;
        
        for row in 0..(height as usize) {
            let py = top_y + row as i32;
            for bi in 0..row_bytes {
                let byte_off = offset + row * row_bytes + bi;
                if byte_off >= data.len() { break; }
                let byte_val = data[byte_off];
                if byte_val == 0 { continue; } // skip empty bytes fast
                for bit in 0..8u8 {
                    let col = bi * 8 + bit as usize;
                    if col >= cw { break; }
                    if byte_val & (0x80 >> bit) != 0 {
                        let _ = display.draw_iter(core::iter::once(
                            embedded_graphics::Pixel(
                                Point::new(cx + col as i32, py),
                                color,
                            )
                        ));
                    }
                }
            }
        }
        cx += cw as i32 + 1; // +1 pixel letter spacing
    }
    cx - x
}

/// Measure text width without drawing
pub fn measure_prop_text(
    text: &str,
    widths: &[u8],
    first_char: u8,
    last_char: u8,
    height: u8,
) -> i32 {
    let mut w: i32 = 0;
    for &ch in text.as_bytes() {
        if ch < first_char || ch > last_char {
            w += (height / 3) as i32;
        } else {
            w += widths[(ch - first_char) as usize] as i32 + 1;
        }
    }
    if w > 0 { w -= 1; } // remove trailing spacing
    w
}


